"use strict";(globalThis.webpackChunkratel_docs=globalThis.webpackChunkratel_docs||[]).push([[716],{6866(e){e.exports=JSON.parse('{"version":{"pluginId":"default","version":"current","label":"Next","banner":null,"badge":false,"noIndex":false,"className":"docs-version-current","isLast":true,"docsSidebars":{"docsSidebar":[{"type":"category","label":"About Ratel","collapsible":true,"collapsed":true,"items":[{"type":"link","href":"/dev/ko/intro/glossary","label":"\uc6a9\uc5b4 \uc815\ub9ac","docId":"intro/glossary","unlisted":false}],"href":"/dev/ko/"},{"type":"link","href":"/dev/ko/getting-started","label":"\uc2dc\uc791\ud558\uae30","docId":"getting-started","unlisted":false},{"type":"link","href":"/dev/ko/ai-connect","label":"AI \uc5f0\uacb0","docId":"ai-connect","unlisted":false},{"type":"category","label":"Teams","collapsible":true,"collapsed":true,"items":[{"type":"link","href":"/dev/ko/teams/create","label":"\ud300 \uc0dd\uc131","docId":"teams/create","unlisted":false},{"type":"link","href":"/dev/ko/teams/sub-teams","label":"\ud558\uc704\ud300 (Sub-teams)","docId":"teams/sub-teams","unlisted":false},{"type":"link","href":"/dev/ko/teams/team-settings","label":"\ud300 \uc124\uc815","docId":"teams/team-settings","unlisted":false}],"href":"/dev/ko/teams/"},{"type":"link","href":"/dev/ko/teams","label":"\ud300 \uc0dd\uc131","docId":"teams","unlisted":false},{"type":"link","href":"/dev/ko/posts","label":"\uac8c\uc2dc\uae00","docId":"posts","unlisted":false},{"type":"category","label":"Spaces","collapsible":true,"collapsed":true,"items":[{"type":"link","href":"/dev/ko/spaces/apps","label":"\uc2a4\ud398\uc774\uc2a4 \uc571 (\ud638\uc2a4\ud2b8 \ub3c4\uad6c)","docId":"spaces/apps","unlisted":false},{"type":"link","href":"/dev/ko/spaces/actions","label":"\uc2a4\ud398\uc774\uc2a4 \uc561\uc158","docId":"spaces/actions","unlisted":false},{"type":"link","href":"/dev/ko/spaces/dashboard","label":"\uc2a4\ud398\uc774\uc2a4 \ub300\uc2dc\ubcf4\ub4dc (\ud638\uc2a4\ud2b8)","docId":"spaces/dashboard","unlisted":false},{"type":"link","href":"/dev/ko/spaces/host-actions","label":"\ud638\uc2a4\ud2b8 \uc561\uc158 (\ud3b8\uc9d1\uae30)","docId":"spaces/host-actions","unlisted":false},{"type":"link","href":"/dev/ko/spaces/reports","label":"\ub9ac\ud3ec\ud2b8 (\ud638\uc2a4\ud2b8)","docId":"spaces/reports","unlisted":false}],"href":"/dev/ko/spaces"},{"type":"category","label":"Essence","collapsible":true,"collapsed":true,"items":[{"type":"link","href":"/dev/ko/essence/my-essence","label":"\ub0b4 Essence","docId":"essence/my-essence","unlisted":false},{"type":"link","href":"/dev/ko/essence/sources","label":"Essence \uc18c\uc2a4","docId":"essence/sources","unlisted":false}],"href":"/dev/ko/essence/"},{"type":"link","href":"/dev/ko/profile","label":"\ud504\ub85c\ud544","docId":"profile","unlisted":false},{"type":"category","label":"Rewards","collapsible":true,"collapsed":true,"items":[{"type":"link","href":"/dev/ko/rewards/xp","label":"\uacbd\ud5d8\uce58 (XP)","docId":"rewards/xp","unlisted":false},{"type":"link","href":"/dev/ko/rewards/points","label":"\ud3ec\uc778\ud2b8","docId":"rewards/points","unlisted":false},{"type":"link","href":"/dev/ko/rewards/credits","label":"\ud06c\ub808\ub527","docId":"rewards/credits","unlisted":false},{"type":"link","href":"/dev/ko/rewards/tokens","label":"\ud1a0\ud070","docId":"rewards/tokens","unlisted":false},{"type":"link","href":"/dev/ko/rewards/incentives","label":"\uc778\uc13c\ud2f0\ube0c","docId":"rewards/incentives","unlisted":false}],"href":"/dev/ko/rewards/"},{"type":"link","href":"/dev/ko/settings","label":"\uc124\uc815","docId":"settings","unlisted":false},{"type":"category","label":"Credentials","collapsible":true,"collapsed":true,"items":[{"type":"link","href":"/dev/ko/credentials/attributes","label":"\uc18d\uc131 \uad00\ub9ac","docId":"credentials/attributes","unlisted":false}],"href":"/dev/ko/credentials/"},{"type":"link","href":"/dev/ko/credentials","label":"\ud06c\ub9ac\ub374\uc15c","docId":"credentials","unlisted":false},{"type":"link","href":"/dev/ko/my-essence","label":"\ub0b4 Essence","docId":"my-essence","unlisted":false},{"type":"link","href":"/dev/ko/essence","label":"Essence \uc18c\uc2a4","docId":"essence","unlisted":false},{"type":"link","href":"/dev/ko/rewards","label":"\ub9ac\uc6cc\ub4dc","docId":"rewards","unlisted":false},{"type":"link","href":"/dev/ko/membership","label":"\uba64\ubc84\uc2ed","docId":"membership","unlisted":false},{"type":"link","href":"/dev/ko/sub-teams","label":"\ud558\uc704\ud300 (Sub-teams)","docId":"sub-teams","unlisted":false},{"type":"link","href":"/dev/ko/team-settings","label":"\ud300 \uc124\uc815","docId":"team-settings","unlisted":false}]},"docs":{"ai-connect":{"id":"ai-connect","title":"AI \uc5f0\uacb0","description":"Ratel\uc740 \uc0ac\uc6a9\uc790\ubcc4\ub85c \ud1b5\ud569 MCP \uc5d4\ub4dc\ud3ec\uc778\ud2b8 \ud558\ub098\ub97c \uc81c\uacf5\ud569\ub2c8\ub2e4. \ud3c9\uc18c \uc4f0\ub294 AI \ud074\ub77c\uc774\uc5b8\ud2b8\uc5d0 \uc5f0\uacb0\ud558\uba74, \uc5b4\uc2dc\uc2a4\ud134\ud2b8\uac00 \ub2f9\uc2e0\uc758 Essence \u2014 \uadf8\ub9ac\uace0 \ub2f9\uc2e0\uc774 \uad6c\ub3c5\ud55c \ub2e4\ub978 Essence House\ub4e4 \u2014 \uc744 \uc77c\uae09 \ub3c4\uad6c\ub85c \ud65c\uc6a9\ud560 \uc218 \uc788\uc2b5\ub2c8\ub2e4.","sidebar":"docsSidebar"},"credentials":{"id":"credentials","title":"\ud06c\ub9ac\ub374\uc15c","description":"\ud06c\ub9ac\ub374\uc15c(Credentials) \ud398\uc774\uc9c0\ub294 \ubcf8\uc778\uc774 \uc99d\uba85\ud55c \uac83\ub4e4\uc774 \ubaa8\uc774\ub294 \uacf3\uc785\ub2c8\ub2e4 \u2014 \ubd84\uc0b0 \uc2dd\ubcc4\uc790(DID), \uadf8 DID \uc5d0 \ubb36\uc778 \uac80\uc99d \uac00\ub2a5\ud55c \ud074\ub808\uc784\ub4e4, \uadf8\ub9ac\uace0 \uadf8 \ubaa8\ub4e0 \uac83\uc744 \ub4b7\ubc1b\uce68\ud558\ub294 \uc554\ud638\ud559\uc801 \uc99d\uba85. \uc2a4\ud398\uc774\uc2a4, Team, \uc678\ubd80 \uac80\uc99d\uc790\uc5d0\uac8c \uc120\ud0dd\uc801\uc73c\ub85c \uacf5\uac1c\ud560 \uc218 \uc788\ub294, \ud504\ub77c\uc774\ubc84\uc2dc\ub97c \ubcf4\uc874\ud558\ub294 \uc2e0\uc6d0 \uc18d\uc131 \uc9c0\uac11\uc774\ub77c\uace0 \ubcf4\uba74 \ub429\ub2c8\ub2e4.","sidebar":"docsSidebar"},"credentials/attributes":{"id":"credentials/attributes","title":"\uc18d\uc131 \uad00\ub9ac","description":"\uc774 \ud398\uc774\uc9c0\ub294 /credentials \ud654\uba74\uc744 \uc9c1\uc811 \ub2e4\ub8e8\ub294 \uac00\uc774\ub4dc\uc785\ub2c8\ub2e4 \u2014 \ud398\uc774\uc9c0 \uad6c\uc131, \ub450 \uac00\uc9c0 \uc778\uc99d \uc218\ub2e8(KYC \uc640 \uc624\ud504\ub77c\uc778 \ucf54\ub4dc), Ratel \uc774 \uc624\ub298 \uc9c0\uc6d0\ud558\ub294 \uc18d\uc131 \uc2ac\ub86f, \uadf8 \uc544\ub798\uc758 \uc554\ud638\ud559\uc801 \uc99d\uba85. \uc790\uaca9\uc99d\uba85\uc774 \uc65c \uc911\uc694\ud55c\uc9c0, \uc5b4\ub514\uc5d0 \uc4f0\uc774\ub294\uc9c0\uc5d0 \ub300\ud55c \uc0c1\uc704 \uac1c\uc694\ub294 \uc790\uaca9\uc99d\uba85 \uac1c\uc694 \ub97c \ucc38\uace0\ud558\uc138\uc694.","sidebar":"docsSidebar"},"credentials/index":{"id":"credentials/index","title":"\uc790\uaca9\uc99d\uba85","description":"Ratel \uc758 \uc790\uaca9\uc99d\uba85(Credential) \uc740 \ubcf8\uc778\uc5d0 \ub300\ud55c \uac80\uc99d \uac00\ub2a5\ud55c \ud074\ub808\uc784\uc785\ub2c8\ub2e4 \u2014 \ub098\uc774, \ud2b9\uc815 \uae30\uad00 \uc18c\uc18d \uc5ec\ubd80, \ucee8\ud37c\ub7f0\uc2a4\uc5d0\uc11c \ubc1b\uc740 \uc77c\ud68c\uc6a9 \ucf54\ub4dc \ub4f1 \u2014 \ubd84\uc0b0 \uc2dd\ubcc4\uc790(DID)\uc5d0 \ubb36\uc774\uace0 Ratel Foundation \uc774 \uc11c\uba85\ud569\ub2c8\ub2e4. \ubcf8\uc778\uc758 DID \uc640 \uac70\uae30\uc5d0 \ubd99\uc740 \uc790\uaca9\uc99d\uba85\ub4e4\uc774 \ud568\uaed8 \ubaa8\uc5ec, \uc2a4\ud398\uc774\uc2a4 \xb7 Team \xb7 \uc678\ubd80 \uac80\uc99d\uc790\uc5d0\uac8c \uc120\ud0dd\uc801\uc73c\ub85c \uacf5\uac1c\ud560 \uc218 \uc788\ub294 \ud504\ub77c\uc774\ubc84\uc2dc \ubcf4\uc874 \uc2e0\uc6d0 \uc9c0\uac11\uc774 \ub429\ub2c8\ub2e4.","sidebar":"docsSidebar"},"essence":{"id":"essence","title":"Essence \uc18c\uc2a4","description":"Essence \uc5d0\ub294 \ucee8\ud2b8\ub864 \ud328\ub110\uc774 \uc788\uc2b5\ub2c8\ub2e4 \u2014 Essence \uc5d0 \ub4e4\uc5b4\uac00\ub294 \ubaa8\ub4e0 \uc785\ub825\uc744 \ud55c \ud398\uc774\uc9c0\uc5d0\uc11c \ubcf4\uace0, \uac80\uc0c9\ud558\uace0, \ub354 \uc774\uc0c1 \uc6d0\ud558\uc9c0 \uc54a\ub294 \ud56d\ubaa9\uc744 \uc815\ub9ac\ud560 \uc218 \uc788\uc5b4\uc694. \uc8fc\uc18c\ub294 \ub2e4\uc74c\uacfc \uac19\uc2b5\ub2c8\ub2e4.","sidebar":"docsSidebar"},"essence/index":{"id":"essence/index","title":"\uc5d0\uc13c\uc2a4","description":"\ubcf8\uc778\uc758 \uc5d0\uc13c\uc2a4(Essence) \ub294 Ratel \uc5d0\uc11c \ud55c \ud65c\ub3d9\uc5d0\uc11c \uc790\ub77c\ub098\ub294 \uac1c\uc778 \uc9c0\uc2dd \ubca0\uc774\uc2a4\uc785\ub2c8\ub2e4 \u2014 \ubc1c\ud589\ud55c \uac8c\uc2dc\uae00, \uc791\uc131\ud55c \ub313\uae00, \ud638\uc2a4\ud305\ud55c \ud3f4\uc774\ub098 \ud034\uc988, \uc2a4\ud398\uc774\uc2a4\uc5d0\uc11c \uc644\ub8cc\ud55c \ubaa8\ub4e0 \uc561\uc158. \ud50c\ub7ab\ud3fc\uc740 \uc774 \uac01\uac01\uc744 EssenceSource \ub85c \ubcc0\ud658\ud569\ub2c8\ub2e4 \u2014 \uac80\uc0c9\uc744 \uc704\ud574 \uc778\ub371\uc2f1\ub418\uace0 \ubcf8\uc778 \uacc4\uc815\uc5d0 \uadc0\uc18d\ub418\uba70 (\uc774\ud6c4 \ub2e8\uacc4\uc5d0\uc11c\ub294) AI \uc5b4\uc2dc\uc2a4\ud134\ud2b8\uac00 \uc9c8\uc758\ud560 \uc218 \uc788\ub3c4\ub85d \ubca1\ud130 \ud45c\ud604\uc73c\ub85c \uc784\ubca0\ub529\ub418\ub294 \uad6c\uc870\ud654\ub41c \uae30\ub85d\uc774\uc5d0\uc694.","sidebar":"docsSidebar"},"essence/my-essence":{"id":"essence/my-essence","title":"\ub0b4 Essence","description":"Essence \ub294 \ucd94\uc0c1\uc801\uc778 \uac1c\ub150\uc774 \uc544\ub2d9\ub2c8\ub2e4 \u2014 \uc571 \uc548\uc5d0 \ub450 \uac1c\uc758 \uc804\uc6a9 \ud398\uc774\uc9c0\uac00 \uc788\uc5b4\uc11c, \ub0b4\uac00 \uc313\uc740 \uac83\uacfc \uadf8\uac83\uc774 \uac00\uc838\ub2e4\uc8fc\ub294 \uac83\uc744 \uc9c1\uc811 \ud655\uc778\ud560 \uc218 \uc788\uc5b4\uc694. My AI (/my-ai) \ub294 Ratel \uc744 \ub0b4 AI \uc5b4\uc2dc\uc2a4\ud134\ud2b8\uc5d0 \uc5f0\uacb0\ud558\ub294 \uacf3\uc785\ub2c8\ub2e4. Character (/me/character) \ub294 \ub0b4 \ud65c\ub3d9\uc774 \ub808\ubca8, \uc2a4\ud0ac \ud3ec\uc778\ud2b8, \uc2a4\ud0ef \ubd80\uc2a4\ud2b8\ub85c \ubcc0\ud558\ub294 \uacf3\uc785\ub2c8\ub2e4.","sidebar":"docsSidebar"},"essence/sources":{"id":"essence/sources","title":"Essence \uc18c\uc2a4","description":"Essence \uc5d0\ub294 \ucee8\ud2b8\ub864 \ud328\ub110\uc774 \uc788\uc2b5\ub2c8\ub2e4 \u2014 Essence \uc5d0 \ub4e4\uc5b4\uac00\ub294 \ubaa8\ub4e0 \uc785\ub825\uc744 \ud55c \ud398\uc774\uc9c0\uc5d0\uc11c \ubcf4\uace0, \uac80\uc0c9\ud558\uace0, \ub354 \uc774\uc0c1 \uc6d0\ud558\uc9c0 \uc54a\ub294 \ud56d\ubaa9\uc744 \uc815\ub9ac\ud560 \uc218 \uc788\uc5b4\uc694. \uc8fc\uc18c\ub294 \ub2e4\uc74c\uacfc \uac19\uc2b5\ub2c8\ub2e4.","sidebar":"docsSidebar"},"getting-started":{"id":"getting-started","title":"\uc2dc\uc791\ud558\uae30","description":"Ratel \u2014 Human Essence Platform \uc5d0 \uc624\uc2e0 \uac83\uc744 \ud658\uc601\ud569\ub2c8\ub2e4. \uc774 \ucc55\ud130\ub294 Ratel \uc5d0\uc11c \ubcf4\ub0b4\ub294 \uccab\ub0a0\uc744 \uc548\ub0b4\ud569\ub2c8\ub2e4. \uac00\uc785\ubd80\ud130 \ud504\ub85c\ud544 \uc124\uc815, \uc678\ubd80 \uacc4\uc815 \uc5f0\uacb0, \uadf8\ub9ac\uace0 \ud654\uba74 \ub458\ub7ec\ubcf4\uae30\uae4c\uc9c0 \ud55c \ubc88\uc5d0 \uc9da\uc5b4\ub4dc\ub9b4\uac8c\uc694.","sidebar":"docsSidebar"},"intro/glossary":{"id":"intro/glossary","title":"\uc6a9\uc5b4 \uc815\ub9ac","description":"\ubcf8 \ubb38\uc11c\uc5d0 \ub4f1\uc7a5\ud558\ub294 Ratel \uc758 \ud575\uc2ec \uc6a9\uc5b4\ub4e4\uc744 \ube60\ub974\uac8c \ud655\uc778\ud560 \uc218 \uc788\ub3c4\ub85d \uc815\ub9ac\ud588\uc2b5\ub2c8\ub2e4. (\uc608\uc815) \ud45c\uc2dc\ub294 \ub85c\ub4dc\ub9f5 \ub2e8\uacc4\uc758 \uae30\ub2a5\uc774\ub77c\ub294 \ub73b\uc785\ub2c8\ub2e4 \u2014 \uae30\ubc18 \uc694\uc18c\ub294 \uc774\ubbf8 \uc874\uc7ac\ud560 \uc218 \uc788\uc9c0\ub9cc, \uc0ac\uc6a9\uc790\uac00 \ub9c8\uc8fc\ud558\ub294 \ud654\uba74\uc740 \uc544\uc9c1 \uc900\ube44 \uc911\uc785\ub2c8\ub2e4.","sidebar":"docsSidebar"},"intro/index":{"id":"intro/index","title":"Ratel \uc18c\uac1c","description":"Ratel\uc740 Human Essence Platform\uc785\ub2c8\ub2e4. \uc2e4\uc81c \uc0ac\ub78c\uc758 \uc0dd\uac01, \ud1b5\ucc30, \uadf8\ub9ac\uace0 \ud65c\ub3d9\uc744 \uae30\ub85d\ud558\uace0 \uc784\ubca0\ub529\ud558\uc5ec, \uc9c1\uc811 \ud65c\uc6a9\ud558\uace0 \uacf5\uc720\ud558\uba70 \uc218\uc775\ud654\ud560 \uc218 \uc788\ub294 \uac1c\uc778 \uc790\uc0b0\uc73c\ub85c \ub9cc\ub4e4\uc5b4 \uc8fc\ub294 \ud50c\ub7ab\ud3fc\uc785\ub2c8\ub2e4. \uc5ec\ub7ec\ubd84\uc774 \uc791\uc131\ud55c \uac8c\uc2dc\uae00, \ucc38\uc5ec\ud55c Space, \ub358\uc9c4 \ud22c\ud45c, \ub0a8\uae34 \ub313\uae00\uacfc \ud1a0\ub860\uc740 \ubaa8\ub450 \uc5ec\ub7ec\ubd84\uc758 Essence(\uc5d0\uc13c\uc2a4) \u2014 \ucc38\uc5ec\ud560\uc218\ub85d \uc790\uc5f0\uc2a4\ub7fd\uac8c \uc790\ub77c\ub098\ub294 \uac1c\uc778 \uc9c0\uc2dd \ubca0\uc774\uc2a4 \u2014 \uc758 \uc77c\ubd80\uac00 \ub429\ub2c8\ub2e4.","sidebar":"docsSidebar"},"membership":{"id":"membership","title":"\uba64\ubc84\uc2ed","description":"\uba64\ubc84\uc2ed\uc740 \ud638\uc2a4\ud2b8\uc640 \ud30c\uc6cc \uc720\uc800\ub97c \uc704\ud55c Ratel \uc758 \ub4f1\uae09 \uc2dc\uc2a4\ud15c\uc785\ub2c8\ub2e4. \ub204\uad6c\ub098 \ubb34\ub8cc\ub85c \uac00\uc785\ud574\uc11c \ud50c\ub7ab\ud3fc\uc744 \uc0ac\uc6a9\ud560 \uc218 \uc788\uace0, \uc720\ub8cc \ub4f1\uae09\uc740 \ubcf4\uc0c1 \uc2a4\ud398\uc774\uc2a4\uc5d0 \uc0ac\uc6a9\ud560 \uc218 \uc788\ub294 \uc6d4\uac04 Credit, \ud06c\ub9ac\uc5d0\uc774\ud130 \ubc43\uc9c0, (\uc0c1\uc704 \ub4f1\uae09\uc5d0\uc11c\ub294) \ucc38\uc5ec\uc790 \uc6d0\ubcf8 \ub370\uc774\ud130 \uc5f4\ub78c \uad8c\ud55c\uc744 \ucd94\uac00\ub85c \uc7a0\uae08 \ud574\uc81c\ud569\ub2c8\ub2e4.","sidebar":"docsSidebar"},"my-essence":{"id":"my-essence","title":"\ub0b4 Essence","description":"Essence \ub294 \ucd94\uc0c1\uc801\uc778 \uac1c\ub150\uc774 \uc544\ub2d9\ub2c8\ub2e4 \u2014 \uc571 \uc548\uc5d0 \ub450 \uac1c\uc758 \uc804\uc6a9 \ud398\uc774\uc9c0\uac00 \uc788\uc5b4\uc11c, \ub0b4\uac00 \uc313\uc740 \uac83\uacfc \uadf8\uac83\uc774 \uac00\uc838\ub2e4\uc8fc\ub294 \uac83\uc744 \uc9c1\uc811 \ud655\uc778\ud560 \uc218 \uc788\uc5b4\uc694. My AI (/my-ai) \ub294 Ratel \uc744 \ub0b4 AI \uc5b4\uc2dc\uc2a4\ud134\ud2b8\uc5d0 \uc5f0\uacb0\ud558\ub294 \uacf3\uc785\ub2c8\ub2e4. Character (/me/character) \ub294 \ub0b4 \ud65c\ub3d9\uc774 \ub808\ubca8, \uc2a4\ud0ac \ud3ec\uc778\ud2b8, \uc2a4\ud0ef \ubd80\uc2a4\ud2b8\ub85c \ubcc0\ud558\ub294 \uacf3\uc785\ub2c8\ub2e4.","sidebar":"docsSidebar"},"posts":{"id":"posts","title":"\uac8c\uc2dc\uae00","description":"\uac8c\uc2dc\uae00\uc774 \uc911\uc694\ud55c \uc774\uc720","sidebar":"docsSidebar"},"profile":{"id":"profile","title":"\ud504\ub85c\ud544","description":"\ud504\ub85c\ud544\uc740 Ratel \uc5d0\uc11c \ub204\uad6c\ub4e0\uc9c0 \ub0b4 \uc774\ub984\uc744 \ub204\ub974\uac70\ub098 \ud578\ub4e4\uc744 \uc8fc\uc18c\ucc3d\uc5d0 \uc785\ub825\ud588\uc744 \ub54c \ub3c4\ucc29\ud558\ub294 \uacf5\uac1c \ud398\uc774\uc9c0\uc785\ub2c8\ub2e4. \uc8fc\uc18c\ub294 \ub2e4\uc74c\uacfc \uac19\uc544\uc694.","sidebar":"docsSidebar"},"rewards":{"id":"rewards","title":"\ub9ac\uc6cc\ub4dc","description":"\ub0b4\uac00 \ucc38\uc5ec\ud55c \ubaa8\ub4e0 \uc2a4\ud398\uc774\uc2a4, \ubc1c\ud589\ud55c \ubaa8\ub4e0 \uac8c\uc2dc\uae00, \ucc38\uc5ec\ub97c \ub04c\uc5b4\ub0b8 \ubaa8\ub4e0 \ub313\uae00\uc774 \u2014 \ub0b4 \uacc4\uc815\uc758 \ub9ac\uc6cc\ub4dc\ub85c \uc313\uc785\ub2c8\ub2e4. \ub9ac\uc6cc\ub4dc \ud398\uc774\uc9c0\ub294 \uadf8\ub3d9\uc548 \uc801\ub9bd\ud55c \uac83, \uc9c0\uae08 \uc801\ub9bd \uc911\uc778 \uac83, \uccad\uad6c \uac00\ub2a5\ud55c \uac83\uc744 \ud55c \ud654\uba74\uc5d0\uc11c \ud655\uc778\ud558\ub294 \uacf3\uc785\ub2c8\ub2e4.","sidebar":"docsSidebar"},"rewards/credits":{"id":"rewards/credits","title":"\ud06c\ub808\ub527","description":"\ud06c\ub808\ub527(Credits) \uc740 \uc2a4\ud398\uc774\uc2a4 \uc561\uc158\uc758 \ubcf4\uc0c1\uc744 \ub4b7\ubc1b\uce68\ud558\ub294 \ud638\uc2a4\ud2b8 \ud380\ub529 \ud1b5\ud654\uc785\ub2c8\ub2e4. \ud3ec\uc778\ud2b8 \uc758 \uc0c1\ub958\uc608\uc694 \u2014 \ud638\uc2a4\ud2b8\uac00 \uc561\uc158\uc758 \ubcf4\uc0c1\uc744 \uc124\uc815\ud560 \ub54c \uc778\uc13c\ud2f0\ube0c \ud480\uc5d0\uc11c \ud06c\ub808\ub527\uc744 \ud560\ub2f9\ud558\uba74, \uc9c0\uae09 \uc2dc\uc810\uc5d0 \uac01 \ud06c\ub808\ub527\uc774 \uadf8 \uc561\uc158\uc744 \uc801\ub9bd\ud55c \ucc38\uc5ec\uc790\uc758 \ud3ec\uc778\ud2b8\ub85c \ubcc0\ud658\ub429\ub2c8\ub2e4.","sidebar":"docsSidebar"},"rewards/incentives":{"id":"rewards/incentives","title":"\uc778\uc13c\ud2f0\ube0c","description":"\uc778\uc13c\ud2f0\ube0c \ud480(Incentive Pool) \uc740 \ud638\uc2a4\ud2b8 \uce21 \ud380\ub529 \ud654\uba74\uc785\ub2c8\ub2e4 \u2014 \ubcf4\uc0c1 \ud1b5\ud654\uac00 \uac1c\ubcc4 \uc561\uc158\uc5d0 \ubd99\uae30 \uc804\uc5d0 \uc0ac\uc804\uc5d0 \ub9c8\ub828\ub418\ub294 \uacf3\uc774\uc5d0\uc694. \uc2a4\ud398\uc774\uc2a4\uc758 \ubcf4\uc0c1 \uacbd\uc81c\uac00 \uc2dc\uc791\ub418\ub294 \uc9c0\uc810\uc785\ub2c8\ub2e4 \u2014 \ud638\uc2a4\ud2b8\uac00 \ud06c\ub808\ub527 \uc73c\ub85c \ud480\uc744 \ucc44\uc6b0\uace0, \ubd84\ubc30 \uaddc\uce59\uc744 \uc124\uc815\ud558\uba74, \uc561\uc158\uc774 \uc644\ub8cc\ub420 \ub54c\ub9c8\ub2e4 \ud480\uc774 \ucc38\uc5ec\uc790\uc5d0\uac8c \uc9c0\uae09\ud574\uc694.","sidebar":"docsSidebar"},"rewards/index":{"id":"rewards/index","title":"\ubcf4\uc0c1","description":"Ratel \uc758 \ubcf4\uc0c1 \uacbd\uc81c\ub294 \ud65c\ub3d9\uc744 \uac00\uce58\ub85c \ubc14\uafb8\ub294 \ub2e4\uc12f \uac00\uc9c0 \ub2e8\uc704\ub85c \uad6c\uc131\ub418\uc5b4 \uc788\uace0, \uac01\uac01 \uc5ed\ud560\uc774 \ub2e4\ub985\ub2c8\ub2e4.","sidebar":"docsSidebar"},"rewards/points":{"id":"rewards/points","title":"\ud3ec\uc778\ud2b8","description":"\ud3ec\uc778\ud2b8(Reward Points, pts) \ub294 Ratel \uc758 \uc778\ud50c\ub7ab\ud3fc \ud3c9\ud310 \ub2e8\uc704\uc774\uc790 \ubcf4\uc0c1 \uc2a4\ud398\uc774\uc2a4 \uc804\ubc18\uc744 \uac00\ub85c\uc9c0\ub974\ub294 \uc801\ub9bd\uc758 \ub2e8\uc704 \uc785\ub2c8\ub2e4. XP \uac00 \ubcf8\uc778\uc758 \uc9c4\ucc99\ub3c4 \ub97c \uce21\uc815\ud55c\ub2e4\uba74, \ud3ec\uc778\ud2b8\ub294 \ubcf8\uc778\uc758 \uc218\ub839 \uc744 \uce21\uc815\ud569\ub2c8\ub2e4 \u2014 \uc0ac\uc774\ud074 \uc548\uc5d0\uc11c \ub204\uc801\ub418\uace0, \uc9c1\uc811 \ud65c\ub3d9 \uc9c0\ud45c(Direct-Activity Index) \uc5d0 \ubc18\uc601\ub418\uba70, \uc6d4\ub9d0\uc5d0 \uccad\uad6c \uac00\ub2a5\ud55c \ud1a0\ud070 \uc591\uc73c\ub85c \uc7a0\uae41\ub2c8\ub2e4.","sidebar":"docsSidebar"},"rewards/tokens":{"id":"rewards/tokens","title":"\ud1a0\ud070","description":"\ud1a0\ud070(Tokens) \uc740 \uacfc\uac70 \uc0ac\uc774\ud074\uc758 \ubcf4\uc0c1 \ud3ec\uc778\ud2b8\ub97c \uc628\uccb4\uc778\uc73c\ub85c \ud45c\ud604\ud55c \uac83\uc785\ub2c8\ub2e4. \ud3ec\uc778\ud2b8\uac00 \uc624\ud504 \ud50c\ub7ab\ud3fc\uccb4\uc778 \ud68c\uacc4\ub77c\uba74, \ud1a0\ud070\uc740 \ubcf8\uc778\uc774 \ud1b5\uc81c\ud558\ub294 \uc9c0\uac11\uc73c\ub85c \uccad\uad6c\ud558\ub294 \ube14\ub85d\uccb4\uc778 \ub124\uc774\ud2f0\ube0c \uc790\uc0b0\uc785\ub2c8\ub2e4. \ucc38\uc5ec\uc5d0\ub294 \uac00\uce58\uac00 \uc788\ub2e4 \ub294 \ud50c\ub7ab\ud3fc\uc758 \uc57d\uc18d\uc744 \uc815\uc0b0\ud558\uace0 \u2014 \ud2b8\ub808\uc800\ub9ac \ub9ac\uc800\ube0c\ub85c 100% \ub2f4\ubcf4\ub429\ub2c8\ub2e4.","sidebar":"docsSidebar"},"rewards/xp":{"id":"rewards/xp","title":"\uacbd\ud5d8\uce58 (XP)","description":"XP (Experience Points) \ub294 Ratel \uc758 \uce90\ub9ad\ud130 \uc131\uc7a5\uc744 \uc774\ub044\ub294 \ud65c\ub3d9 \uae30\ubc18 \ub2e8\uc704\uc785\ub2c8\ub2e4. \uc2a4\ud398\uc774\uc2a4 \uc561\uc158\uc744 \uc644\ub8cc\ud560 \ub54c\ub9c8\ub2e4 SpaceActivity \uac00 \ud55c \ud589 \uae30\ub85d\ub418\uace0, \uadf8 \ud589\uc774 \uc815\ud574\uc9c4 \uc591\uc758 XP \ub97c \uce90\ub9ad\ud130 \ud569\uacc4\uc5d0 \uc801\ub9bd\ud569\ub2c8\ub2e4. XP \uc790\uccb4\ub294 \uc9c1\uc811 \ud604\uae08\ud654\ub418\uc9c0 \uc54a\uc544\uc694 \u2014 XP \uc758 \uc5ed\ud560\uc740 \ub808\ubca8\uc744 \uc62c\ub9ac\uace0, \uc2a4\ud0ac \ud3ec\uc778\ud2b8(SP) \ub97c \uc8fc\uace0, \uadf8 SP \ub85c \uc0b4 \uc218 \uc788\ub294 \ubd80\uc2a4\ud2b8\ub97c \ud1b5\ud574 \ub2e4\ub978 \ub2e8\uc704\ub4e4\uc758 \uc801\ub9bd\ub7c9\uc744 \ub298\ub9ac\ub294 \uac70\uc608\uc694.","sidebar":"docsSidebar"},"settings":{"id":"settings","title":"\uc124\uc815","description":"\uacc4\uc815\uc5d0 \uad00\ud55c \ubaa8\ub4e0 \uac83\uc744 \ud55c\uacf3\uc5d0\uc11c \ubc14\uafc0 \uc218 \uc788\ub294 \ud398\uc774\uc9c0\uc785\ub2c8\ub2e4 \u2014 \uc5b4\ub5bb\uac8c \ubcf4\uc77c\uc9c0, \uc5b4\ub5bb\uac8c \ub85c\uadf8\uc778\ud560\uc9c0, \uc5b4\ub5a4 \ud50c\ub79c\uc744 \uc4f8\uc9c0, AI \uc5d0\uc774\uc804\ud2b8\uac00 \ub0b4 Ratel \ub370\uc774\ud130\uc5d0 \uc5b4\ub5bb\uac8c \uc811\uc18d\ud560\uc9c0\uae4c\uc9c0.","sidebar":"docsSidebar"},"spaces/actions":{"id":"spaces/actions","title":"\uc2a4\ud398\uc774\uc2a4 \uc561\uc158","description":"Apps \uac00 \ud638\uc2a4\ud2b8\uc758 \ub3c4\uad6c\ud568\uc774\ub77c\uba74, \uc561\uc158(Action) \uc740 \ucc38\uc5ec\uc790\uc758 \ud018\uc2a4\ud2b8 \ubcf4\ub4dc\uc785\ub2c8\ub2e4. \uac01 \uc561\uc158\uc740 \ud638\uc2a4\ud2b8\uac00 \ubcf8\uc778\uc5d0\uac8c \ubd80\ud0c1\ud558\ub294 \ud55c \uac00\uc9c0 \uc77c\uc785\ub2c8\ub2e4 \u2014 \ubb34\uc5b8\uac00\uc5d0 \ud22c\ud45c\ud558\uae30, \ud1a0\ub860\uc5d0 \uc758\uacac \ub0a8\uae30\uae30, \ud034\uc988 \ud480\uae30, \uba87 \uba85 \ud314\ub85c\uc6b0\ud558\uae30, \ubbf8\ud305\uc5d0 RSVP \u2014 \uadf8\ub9ac\uace0 \uc561\uc158\uc744 \ub05d\ub0b4\uba74 \uc2a4\ud398\uc774\uc2a4 \ubcf4\uc0c1\uc758 \ud55c \ubaab\uc744 \uac00\uc838\uac00\uba74\uc11c, \ubcf8\uc778\uc774 \ubb34\uc5c7\uc744 \uc0dd\uac01\ud558\ub294\uc9c0\uc5d0 \ub300\ud55c \uad6c\uc870\ud654\ub41c \uc2e0\ud638\uac00 Essence \uc5d0 \uc313\uc785\ub2c8\ub2e4.","sidebar":"docsSidebar"},"spaces/apps":{"id":"spaces/apps","title":"\uc2a4\ud398\uc774\uc2a4 \uc571 (\ud638\uc2a4\ud2b8 \ub3c4\uad6c)","description":"\uc2a4\ud398\uc774\uc2a4\uc758 \ud638\uc2a4\ud2b8\ub77c\uba74, \uc571(App) \uc740 \uc2a4\ud398\uc774\uc2a4\ub97c \ub9cc\ub4e4\uae30 \uc704\ud574 \ub07c\uc6cc \ub123\ub294 \ube4c\ub529 \ube14\ub85d\uc785\ub2c8\ub2e4. \uac01 \uc571\uc740 \ud55c \uac00\uc9c0 \uc77c\uc744 \ub2f4\ub2f9\ud569\ub2c8\ub2e4 \u2014 \uc548\ub0b4 \uac8c\uc2dc, \ud30c\uc77c \uacf5\uc720, \ucc38\uc5ec\uc790\uc5d0\uac8c \ud22c\ud45c \uc694\uccad, AI \ubcf4\uc870 \ub9ac\ud3ec\ud2b8 \uc0dd\uc131, \ubcf4\uc0c1 \ubd84\ubc30 \u2014 \uc624\ub298 \ud544\uc694 \uc5c6\ub294 \uc571\uc740 \uadf8\ub0e5 \ube7c\ub450\uba74 \ub429\ub2c8\ub2e4.","sidebar":"docsSidebar"},"spaces/dashboard":{"id":"spaces/dashboard","title":"\uc2a4\ud398\uc774\uc2a4 \ub300\uc2dc\ubcf4\ub4dc (\ud638\uc2a4\ud2b8)","description":"\ub300\uc2dc\ubcf4\ub4dc\ub294 \ud638\uc2a4\ud2b8\uc758 \\"\ub0b4 \uc2a4\ud398\uc774\uc2a4, \uc624\ub298 \uc5b4\ub5bb\uac8c \ub3cc\uc544\uac00\uace0 \uc788\ub098\\" \ud654\uba74\uc785\ub2c8\ub2e4 \u2014 \uc2a4\ud0ef \uce74\ub4dc \ud55c \ubb36\uc74c\uacfc \ucc38\uc5ec\uc790 \ub7ad\ud0b9 \ud45c\uac00 \ud55c \ud654\uba74\uc5d0 \ubaa8\uc5ec \uc788\uace0, \uc0ac\ub78c\ub4e4\uc774 \ud65c\ub3d9\ud560\uc218\ub85d \ub77c\uc774\ube0c\ub85c \uac31\uc2e0\ub429\ub2c8\ub2e4. \uc704\uce58\ub294 \ub2e4\uc74c\uacfc \uac19\uc2b5\ub2c8\ub2e4.","sidebar":"docsSidebar"},"spaces/host-actions":{"id":"spaces/host-actions","title":"\ud638\uc2a4\ud2b8 \uc561\uc158 (\ud3b8\uc9d1\uae30)","description":"\uc774 \ucc55\ud130\ub294 \uc2a4\ud398\uc774\uc2a4 \uc561\uc158 \uc758 \ud638\uc2a4\ud2b8 \uce21 \uc9dd\uc785\ub2c8\ub2e4. \ucc38\uc5ec\uc790 \ucc55\ud130\uac00 \uc561\uc158\uc774 \ucc38\uc5ec\uc790\uc5d0\uac8c \uc5b4\ub5bb\uac8c \ubcf4\uc774\ub294\uc9c0 \ub97c \ub2e4\ub918\ub2e4\uba74, \uc774 \ucc55\ud130\ub294 \ud638\uc2a4\ud2b8\uc778 \ub2f9\uc2e0\uc774 \uac01 \uc561\uc158 \uc720\ud615\uc744 \uc5b4\ub5bb\uac8c \ub9cc\ub4e4\uace0 \ud3b8\uc9d1 \ud558\ub294\uc9c0\ub97c \uc548\ub0b4\ud569\ub2c8\ub2e4.","sidebar":"docsSidebar"},"spaces/index":{"id":"spaces/index","title":"\uc2a4\ud398\uc774\uc2a4","description":"\uc2a4\ud398\uc774\uc2a4\ub294 Ratel \ud65c\ub3d9\uc774 \uc77c\uc5b4\ub098\ub294 \uc544\ub808\ub098\uc785\ub2c8\ub2e4. \ud1a0\ub860, \ud22c\ud45c, \ud034\uc988, \ud314\ub85c\uc6b0 \ud018\uc2a4\ud2b8, \uc77c\uc815\uc774 \uc7a1\ud78c \ubbf8\ud305 \u2014 \ucee4\ubba4\ub2c8\ud2f0\ub97c \uce21\uc815 \uac00\ub2a5\ud55c \ub300\ud654\ub85c \ubc14\uafb8\ub294 \ubaa8\ub4e0 \ud65c\ub3d9\uc774 \uc2a4\ud398\uc774\uc2a4 \uc548\uc5d0\uc11c \ubc8c\uc5b4\uc9d1\ub2c8\ub2e4. \uc2a4\ud398\uc774\uc2a4\uc5d0\uc11c \ud638\uc2a4\ud2b8\ub294 \ucc38\uc5ec\uc790\uc5d0\uac8c \ubcf4\uc5ec\uc904 \ubaa8\uc2b5\uc744 \ub9cc\ub4e4\uace0, \ucc38\uc5ec\uc790\ub294 \ud65c\ub3d9\uc744 \ud1b5\ud574 Essence \ub97c \uc313\uc2b5\ub2c8\ub2e4.","sidebar":"docsSidebar"},"spaces/reports":{"id":"spaces/reports","title":"\ub9ac\ud3ec\ud2b8 (\ud638\uc2a4\ud2b8)","description":"\ub9ac\ud3ec\ud2b8(Report) \ub294 \ud638\uc2a4\ud2b8\uac00 \uc790\uc2e0\uc758 \uc2a4\ud398\uc774\uc2a4\uc5d0\uc11c \uc77c\uc5b4\ub09c \uc77c\uc744 \uc885\ud569\ud574 \ubc1c\ud589\ud558\ub294 \uacb0\uacfc\ubb3c\uc785\ub2c8\ub2e4 \u2014 \ucc38\uc5ec\uc790\ub4e4\uc774 \uc5b4\ub5bb\uac8c \uc0dd\uac01\ud588\uace0, \uc5b4\ub514\uc11c \ud569\uc758\ud588\uace0, \uc5b4\ub514\uc11c \uac08\ub838\uace0, \ubb34\uc5c7\uc774 \ub450\ub4dc\ub7ec\uc84c\ub294\uc9c0\ub97c \uc815\ub9ac\ud55c \ubb38\uc11c\uc608\uc694. Ratel \uc5d0\ub294 \ud568\uaed8 \ub3d9\uc791\ud558\ub294 \ub450 \uac1c\uc758 \ub9ac\ud3ec\ud2b8 \ud654\uba74\uc774 \uc788\uc2b5\ub2c8\ub2e4.","sidebar":"docsSidebar"},"sub-teams":{"id":"sub-teams","title":"\ud558\uc704\ud300 (Sub-teams)","description":"\ud558\uc704\ud300\uc740 \uc0c1\uc704 Team \uc774 \ub2e4\ub978 Team \uc744 \uc790\uc2e0\uc758 \uc6b0\uc0b0 \uc544\ub798\uc5d0 \uacf5\uc2dd\uc801\uc73c\ub85c \uc778\uc815\ud558\ub294 \ubc29\uc2dd\uc785\ub2c8\ub2e4 \u2014 \ucc55\ud130, \uc6cc\ud0b9 \uadf8\ub8f9, \ud30c\ud2b8\ub108 \uc140\ucc98\ub7fc \ud761\uc218\ud558\uc9c0 \uc54a\uc73c\uba74\uc11c \uad00\uacc4\ub97c \ub9fa\ub294 \uac70\uc608\uc694. \uc591\ucabd \ubaa8\ub450 \uc790\uc2e0\uc758 \uac8c\uc2dc\uae00, \uba64\ubc84, \ud2b8\ub808\uc800\ub9ac, \uc2a4\ud398\uc774\uc2a4\ub97c \uadf8\ub300\ub85c \uc720\uc9c0\ud558\uc9c0\ub9cc, \ub450 Team \uc0ac\uc774\uc758 \uad00\uacc4\ub294 \uaddc\uc815 \xb7 \ubb38\uc11c \xb7 \uacf5\uc9c0 \xb7 \ub204\uac00 \ub204\uad6c\uc758 \ud558\uc704\ud300\uc778\uc9c0\uc5d0 \ub300\ud55c \uacf5\uac1c \ub4f1\ub85d\ubd80\ub97c \uac16\ucd98 \ud50c\ub7ab\ud3fc \uc704\uc758 \ub9c1\ud06c \uac00 \ub429\ub2c8\ub2e4.","sidebar":"docsSidebar"},"team-settings":{"id":"team-settings","title":"\ud300 \uc124\uc815","description":"\ud300 \uc124\uc815(Team Settings) \uc740 Team \uc758 \uad00\ub9ac\uc790\uac00 Team \uc790\uccb4\ub97c \uad00\ub9ac\ud558\ub294 \uacf3\uc785\ub2c8\ub2e4 \u2014 \uacf5\uac1c \uc815\uccb4\uc131, \uba64\ubc84\uc640 \uc5ed\ud560, \ub9e4\uc6d4 Credit \uc744 \uc9c0\uae09\ud558\ub294 \uad6c\ub3c5, \uadf8\ub9ac\uace0 (\ud544\uc694\ud558\ub2e4\uba74) \uc0ad\uc81c \ud750\ub984\uae4c\uc9c0. \uc774 \ud654\uba74\uc740 Team \uc758 \uad00\ub9ac\uc790(administrator) \uc2dc\uc810 \uc785\ub2c8\ub2e4 \u2014 \uacf5\uac1c \ud504\ub85c\ud544\uacfc \ud53c\ub4dc\ub294 \ud300 \ub9cc\ub4e4\uae30 \ucc55\ud130\ub97c \ucc38\uace0\ud558\uc138\uc694.","sidebar":"docsSidebar"},"teams":{"id":"teams","title":"\ud300 \uc0dd\uc131","description":"\uc65c \ud300\uc778\uac00\uc694?","sidebar":"docsSidebar"},"teams/create":{"id":"teams/create","title":"\ud300 \uc0dd\uc131","description":"\uc774 \ud398\uc774\uc9c0\ub294 \ud300\uc744 \ub9cc\ub4e4\uace0 \uc790\ub9ac \uc7a1\uae30\uae4c\uc9c0\uc758 \ud750\ub984\uc744 \uc548\ub0b4\ud569\ub2c8\ub2e4 \u2014 \uc0dd\uc131 \ud31d\uc5c5, \ub9cc\ub4e4\uace0 \ub4e4\uc5b4\uac00\uba74 \ubcf4\uc774\ub294 \uc544\ub808\ub098 \ud0ed\ub4e4, \uba64\ubc84 \uc5ed\ud560, \ubc1c\ud589 \uc601\uc5ed (\uac8c\uc2dc\uae00 / \ub4dc\ub798\ud504\ud2b8 / \ubcf4\uc0c1 / \uba64\ubc84\uc2ed), \ud300 \uad6c\ub3c5, \ub0b4\uc7a5\ub41c DAO, \uadf8\ub9ac\uace0 \ud558\uc704\ud300 \ud750\ub984\uc758 \uc9e7\uc740 \uc778\ub371\uc2a4. \ud300\uc774 \ubb34\uc5c7\uc774\uace0 \ucc55\ud130\uc758 \ub098\uba38\uc9c0\uac00 \uc5b4\ub514\ub85c \uc774\uc5b4\uc9c0\ub294\uc9c0\uc5d0 \ub300\ud55c \ud070 \uadf8\ub9bc\uc740 \ud300 \uac1c\uc694 \ub97c \ucc38\uace0\ud558\uc138\uc694.","sidebar":"docsSidebar"},"teams/index":{"id":"teams/index","title":"\ud300","description":"Ratel \uc758 Team \uc740 \uc790\uccb4 \ud578\ub4e4, \uc790\uccb4 \uc544\ub808\ub098 \ud398\uc774\uc9c0, \uc790\uccb4 \ud2b8\ub808\uc800\ub9ac\ub97c \uac00\uc9c4 \ub2e4\uc778 \ud611\uc5c5 \ub2e8\uc704\uc785\ub2c8\ub2e4. \ud568\uaed8 \ub9cc\ub4e0 \uacb0\uacfc\ubb3c\uc740 \uac1c\uc778\uc774 \uc544\ub2cc \ud300\uc758 \uc774\ub984\uc73c\ub85c \ub0a8\uace0, \ud300\uc740 \uac8c\uc2dc\uae00\uc744 \ubc1c\ud589\ud558\uace0, \ubcf4\uc0c1\uc774 \uac78\ub9b0 \uc2a4\ud398\uc774\uc2a4\ub97c \uc6b4\uc601\ud558\uace0, \uc218\uc775\uc744 \ubd84\ubc30\ud558\uace0, \ub0b4\uc7a5\ub41c DAO \ub85c \uc2a4\uc2a4\ub85c\ub97c \ud1b5\uce58\ud569\ub2c8\ub2e4.","sidebar":"docsSidebar"},"teams/sub-teams":{"id":"teams/sub-teams","title":"\ud558\uc704\ud300 (Sub-teams)","description":"\ud558\uc704\ud300\uc740 \uc0c1\uc704 Team \uc774 \ub2e4\ub978 Team \uc744 \uc790\uc2e0\uc758 \uc6b0\uc0b0 \uc544\ub798\uc5d0 \uacf5\uc2dd\uc801\uc73c\ub85c \uc778\uc815\ud558\ub294 \ubc29\uc2dd\uc785\ub2c8\ub2e4 \u2014 \ucc55\ud130, \uc6cc\ud0b9 \uadf8\ub8f9, \ud30c\ud2b8\ub108 \uc140\ucc98\ub7fc \ud761\uc218\ud558\uc9c0 \uc54a\uc73c\uba74\uc11c \uad00\uacc4\ub97c \ub9fa\ub294 \uac70\uc608\uc694. \uc591\ucabd \ubaa8\ub450 \uc790\uc2e0\uc758 \uac8c\uc2dc\uae00, \uba64\ubc84, \ud2b8\ub808\uc800\ub9ac, \uc2a4\ud398\uc774\uc2a4\ub97c \uadf8\ub300\ub85c \uc720\uc9c0\ud558\uc9c0\ub9cc, \ub450 Team \uc0ac\uc774\uc758 \uad00\uacc4\ub294 \uaddc\uc815 \xb7 \ubb38\uc11c \xb7 \uacf5\uc9c0 \xb7 \ub204\uac00 \ub204\uad6c\uc758 \ud558\uc704\ud300\uc778\uc9c0\uc5d0 \ub300\ud55c \uacf5\uac1c \ub4f1\ub85d\ubd80\ub97c \uac16\ucd98 \ud50c\ub7ab\ud3fc \uc704\uc758 \ub9c1\ud06c \uac00 \ub429\ub2c8\ub2e4.","sidebar":"docsSidebar"},"teams/team-settings":{"id":"teams/team-settings","title":"\ud300 \uc124\uc815","description":"\ud300 \uc124\uc815(Team Settings) \uc740 Team \uc758 \uad00\ub9ac\uc790\uac00 Team \uc790\uccb4\ub97c \uad00\ub9ac\ud558\ub294 \uacf3\uc785\ub2c8\ub2e4 \u2014 \uacf5\uac1c \uc815\uccb4\uc131, \uba64\ubc84\uc640 \uc5ed\ud560, \ub9e4\uc6d4 Credit \uc744 \uc9c0\uae09\ud558\ub294 \uad6c\ub3c5, \uadf8\ub9ac\uace0 (\ud544\uc694\ud558\ub2e4\uba74) \uc0ad\uc81c \ud750\ub984\uae4c\uc9c0. \uc774 \ud654\uba74\uc740 Team \uc758 \uad00\ub9ac\uc790(administrator) \uc2dc\uc810 \uc785\ub2c8\ub2e4 \u2014 \uacf5\uac1c \ud504\ub85c\ud544\uacfc \ud53c\ub4dc\ub294 \ud300 \uc0dd\uc131 \uc744 \ucc38\uace0\ud558\uc138\uc694.","sidebar":"docsSidebar"}}}}')}}]);